import React from 'react';

const CONFIG = {
  'open':        { bg: 'var(--open-bg)',  color: 'var(--open-text)',  border: 'var(--open-border)',  label: 'Open' },
  'in-progress': { bg: 'var(--prog-bg)',  color: 'var(--prog-text)',  border: 'var(--prog-border)',  label: 'In Progress' },
  'done':        { bg: 'var(--done-bg)',  color: 'var(--done-text)',  border: 'var(--done-border)',  label: 'Done' },
};

export default function Badge({ status }) {
  const cfg = CONFIG[status] || CONFIG['open'];
  return (
    <span style={{
      fontFamily: 'var(--font-mono)',
      fontSize: 10,
      fontWeight: 600,
      padding: '3px 10px',
      borderRadius: 20,
      letterSpacing: '0.08em',
      textTransform: 'uppercase',
      background: cfg.bg,
      color: cfg.color,
      border: `1px solid ${cfg.border}`,
    }}>
      {cfg.label}
    </span>
  );
}
